# agent_service/app.py — a complete Flask agent API in one file
from __future__ import annotations

import os
import uuid
from dataclasses import dataclass, field
from typing import Any

from flask import Flask, abort, jsonify, request

app = Flask(__name__)
app.config["MAX_CONTENT_LENGTH"] = 1 * 1024 * 1024  # 1 MB hard cap on request body

# ---------------------------------------------------------------------------
# In-memory job store (replace with Redis in production)
# ---------------------------------------------------------------------------
_jobs: dict[str, dict[str, Any]] = {}


@dataclass
class AgentRequest:
    prompt: str
    session_id: str = field(default_factory=lambda: str(uuid.uuid4()))
    max_steps: int = 10

    @classmethod
    def from_json(cls, data: dict) -> "AgentRequest":
        if not isinstance(data.get("prompt"), str) or not data["prompt"].strip():
            raise ValueError("prompt must be a non-empty string")
        max_steps = data.get("max_steps", 10)
        if not isinstance(max_steps, int) or not (1 <= max_steps <= 50):
            raise ValueError("max_steps must be an integer between 1 and 50")
        return cls(prompt=data["prompt"].strip(), max_steps=max_steps)


# ---------------------------------------------------------------------------
# Error handlers
# ---------------------------------------------------------------------------

@app.errorhandler(400)
def bad_request(e):
    return jsonify({"error": "bad_request", "detail": str(e)}), 400

@app.errorhandler(404)
def not_found(e):
    return jsonify({"error": "not_found"}), 404

@app.errorhandler(413)
def request_too_large(e):
    return jsonify({"error": "payload_too_large"}), 413


# ---------------------------------------------------------------------------
# Routes
# ---------------------------------------------------------------------------

@app.post("/agent/run")
def run_agent():
    data = request.get_json(force=True, silent=True) or {}
    try:
        req = AgentRequest.from_json(data)
    except ValueError as exc:
        abort(400, description=str(exc))

    job_id = str(uuid.uuid4())
    _jobs[job_id] = {"status": "queued", "prompt": req.prompt, "result": None}
    # In a real service: enqueue to Celery here
    # agent_task.delay(job_id, req.prompt, req.max_steps)
    _jobs[job_id]["status"] = "done"
    _jobs[job_id]["result"] = f"[sync] processed: {req.prompt[:50]}"

    return jsonify({"job_id": job_id, "status": "done", "result": _jobs[job_id]["result"]}), 200


@app.get("/agent/jobs/<job_id>")
def get_job(job_id: str):
    job = _jobs.get(job_id)
    if job is None:
        abort(404)
    return jsonify({"job_id": job_id, **job}), 200


@app.get("/health")
def health():
    return jsonify({"status": "ok"}), 200


if __name__ == "__main__":
    # Never expose this in production — use gunicorn instead
    app.run(host="127.0.0.1", port=5000, debug=False)

